/**
 * Mise à jour des cartes KPI
 */
function updateKPICards() {
    if (!dashboardData.statistics) return;
    
    const stats = dashboardData.statistics;
    
    // Animation des compteurs
    animateCounter('#kpi-active-companies .counter', stats.activeCompanies);
    animateCounter('#kpi-alerts .counter', stats.alertsCount);
    animateCounter('#kpi-tasks .counter', stats.tasksCount);
    animateCounter('#kpi-compliance .counter', stats.complianceRate);
    
    // Mise à jour des badges de notification
    updateNotificationBadge(stats.alertsCount);
}

/**
 * Animation des compteurs
 */
function animateCounter(selector, target) {
    const element = document.querySelector(selector);
    if (!element) return;
    
    const start = 0;
    const duration = 1500;
    const startTime = performance.now();
    
    function updateCounter(currentTime) {
        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1);
        
        // Fonction d'easing
        const easeOut = 1 - Math.pow(1 - progress, 3);
        const current = Math.floor(start + (target - start) * easeOut);
        
        element.textContent = current;
        
        if (progress < 1) {
            requestAnimationFrame(updateCounter);
        } else {
            element.textContent = target;
            element.classList.add('counter-animate');
        }
    }
    
    requestAnimationFrame(updateCounter);
}

