/**
 * Recherche rapide d'entreprises
 */
function performQuickSearch() {
    const query = document.getElementById('searchInput').value.trim();
    const resultsContainer = document.getElementById('searchResults');
    
    if (query.length < 3) {
        resultsContainer.innerHTML = `
            <div class="text-center text-muted py-4">
                <i class="bi bi-search fs-1"></i>
                <p class="mt-2">Saisissez au moins 3 caractères pour lancer la recherche</p>
            </div>
        `;
        return;
    }
    
    // Simulation de la recherche
    const results = searchCompanies(query);
    
    if (results.length === 0) {
        resultsContainer.innerHTML = `
            <div class="text-center text-muted py-4">
                <i class="bi bi-inbox fs-1"></i>
                <p class="mt-2">Aucun résultat trouvé pour "${query}"</p>
            </div>
        `;
        return;
    }
    
    resultsContainer.innerHTML = results.map(company => `
        <div class="search-result-item" onclick="openCompanyDetails('${company.id}')">
            <div class="d-flex justify-content-between align-items-start">
                <div>
                    <h6 class="mb-1">${company.name}</h6>
                    <div class="search-result-meta">
                        <span class="me-3"><strong>NIF:</strong> ${company.nif}</span>
                        <span class="me-3"><strong>Segment:</strong> ${company.segment}</span>
                        <span class="badge ${getStatusBadgeClass(company.status)}">${company.status}</span>
                    </div>
                </div>
                <i class="bi bi-arrow-right text-primary"></i>
            </div>
        </div>
    `).join('');
    
    logActivity('search_performed', { query, resultsCount: results.length });
}

/**
 * Ouverture du modal de création d'entreprise
 */
function openCreateModal() {
    const modal = new bootstrap.Modal(document.getElementById('createCompanyModal'));
    modal.show();
    
    // Réinitialisation du formulaire
    document.getElementById('createCompanyForm').reset();
    
    logActivity('create_modal_opened');
}

/**
 * Sauvegarde d'une nouvelle entreprise
 */
function saveNewCompany() {
    const form = document.getElementById('createCompanyForm');
    const formData = new FormData(form);
    
    // Validation des champs obligatoires
    const requiredFields = ['companyName', 'companyNIF', 'companySegment', 'companySector'];
    const missingFields = requiredFields.filter(field => !document.getElementById(field).value.trim());
    
    if (missingFields.length > 0) {
        showAlert('Veuillez remplir tous les champs obligatoires', 'warning');
        return;
    }
    
    // Création de l'objet entreprise
    const newCompany = {
        id: generateId(),
        name: document.getElementById('companyName').value.trim(),
        nif: document.getElementById('companyNIF').value.trim(),
        segment: document.getElementById('companySegment').value,
        sector: document.getElementById('companySector').value,
        address: document.getElementById('companyAddress').value.trim(),
        status: 'PENDING_KYC',
        createdAt: new Date().toISOString(),
        createdBy: userProfile.name
    };
    
    // Ajout à la liste des entreprises
    if (!dashboardData.companies) {
        dashboardData.companies = [];
    }
    
    dashboardData.companies.push(newCompany);
    
    // Mise à jour des statistiques
    dashboardData.statistics.totalCompanies++;
    
    // Sauvegarde
    saveDashboardData();
    
    // Fermeture du modal
    bootstrap.Modal.getInstance(document.getElementById('createCompanyModal')).hide();
    
    // Notification de succès
    showAlert(`Entreprise "${newCompany.name}" créée avec succès`, 'success');
    
    // Actualisation du dashboard
    updateKPICards();
    
    // Journalisation
    logActivity('company_created', { companyId: newCompany.id, companyName: newCompany.name });
}

/**
 * =====================================
 * EXPORT PDF
 * =====================================
 */

/**
 * Export du dashboard en PDF
 */
function exportDashboard() {
    try {
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF();
        
        // Configuration
        const pageWidth = doc.internal.pageSize.width;
        const pageHeight = doc.internal.pageSize.height;
        const margin = 20;
        
        // En-tête BCI élégant
        addPDFHeader(doc, pageWidth, margin);
        
        let yPosition = 60;
        
        // Titre du rapport
        doc.setFontSize(20);
        doc.setTextColor(52, 52, 115);
        doc.text('Tableau de Bord - Module Entreprises Clientes', margin, yPosition);
        
        yPosition += 15;
        doc.setFontSize(12);
        doc.setTextColor(100);
        doc.text(`Généré le ${formatDateTime(new Date())} par ${userProfile.name}`, margin, yPosition);
        
        yPosition += 25;
        
        // Section KPI
        addPDFSection(doc, 'Indicateurs Clés de Performance', margin, yPosition);
        yPosition += 15;
        
        const stats = dashboardData.statistics;
        const kpiData = [
            ['Entreprises Actives', stats.activeCompanies.toString()],
            ['Alertes en Cours', stats.alertsCount.toString()],
            ['Tâches en Attente', stats.tasksCount.toString()],
            ['Taux de Conformité', `${stats.complianceRate}%`]
        ];
        
        addPDFTable(doc, ['Indicateur', 'Valeur'], kpiData, margin, yPosition);
        yPosition += (kpiData.length * 8) + 20;
        
        // Section Alertes
        if (yPosition > pageHeight - 80) {
            doc.addPage();
            yPosition = margin;
        }
        
        addPDFSection(doc, 'Alertes Prioritaires', margin, yPosition);
        yPosition += 15;
        
        const alertsData = dashboardData.alerts.slice(0, 5).map(alert => [
            alert.title,
            getPriorityLabel(alert.priority),
            formatDate(alert.createdAt)
        ]);
        
        addPDFTable(doc, ['Alerte', 'Priorité', 'Date'], alertsData, margin, yPosition);
        
        // Pied de page
        addPDFFooter(doc, pageWidth, pageHeight, margin);
        
        // Téléchargement
        const fileName = `Tableau_de_Bord_BCI_${formatDate(new Date(), 'YYYYMMDD')}.pdf`;
        doc.save(fileName);
        
        showAlert('Rapport PDF généré avec succès', 'success');
        logActivity('dashboard_exported', { format: 'PDF', fileName });
        
    } catch (error) {
        console.error('❌ Erreur lors de l\'export PDF:', error);
        showAlert('Erreur lors de la génération du PDF', 'danger');
    }
}

/**
 * Ajout de l'en-tête PDF élégant
 */
function addPDFHeader(doc, pageWidth, margin) {
    // Fond en-tête
    doc.setFillColor(52, 52, 115);
    doc.rect(0, 0, pageWidth, 35, 'F');
    
    // Logo officiel en base64
    doc.addImage("data:image/png;base64,", "PNG", 10, 7, 20, 20 );
    
    
    // Titre institution
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(18);
    doc.setFont('helvetica', 'bold');
    doc.text('BANQUE POUR LE COMMERCE ET L\'INDUSTRIE', margin + 20, 15);
    doc.setFontSize(10);
    doc.text('Avenue de la République, Sandervalia, Kaloum, BP : 359, Conakry, République de Guinée', margin + 20, 23);
}

/**
 * Ajout d'une section dans le PDF
 */
function addPDFSection(doc, title, x, y) {
    doc.setFontSize(14);
    doc.setTextColor(52, 52, 115);
    doc.text(title, x, y);
    
    // Ligne de séparation
    doc.setDrawColor(52, 52, 115);
    doc.line(x, y + 2, x + 100, y + 2);
}

/**
 * Ajout d'un tableau dans le PDF
 */
function addPDFTable(doc, headers, data, x, y) {
    doc.setFontSize(10);
    doc.setTextColor(0);
    
    // En-têtes
    doc.setFont('helvetica', 'bold');
    headers.forEach((header, index) => {
        doc.text(header, x + (index * 60), y);
    });
    
    // Données
    doc.setFont('helvetica', 'normal');
    data.forEach((row, rowIndex) => {
        row.forEach((cell, cellIndex) => {
            doc.text(cell.toString(), x + (cellIndex * 60), y + 8 + (rowIndex * 8));
        });
    });
}

/**
 * Ajout du pied de page PDF
 */
function addPDFFooter(doc, pageWidth, pageHeight, margin) {
    const footerY = pageHeight - 20;
    
    doc.setFontSize(8);
    doc.setTextColor(100);
    doc.text('Document confidentiel - Usage restreint BCI - Tous droits réservés', margin, footerY);
    doc.text(`Page 1 - ${CONFIG.appName} v${CONFIG.version}`, pageWidth - margin, footerY, { align: 'right' });
}

