/**
 * Actualisation du dashboard
 */
function refreshDashboard() {
    showAlert('Actualisation du tableau de bord...', 'info');
    
    // Simulation du rechargement des données
    setTimeout(() => {
        loadDashboardData();
        updateKPICards();
        updateAlertsList();
        updateTasksList();
        
        // Mise à jour des graphiques
        if (charts.evolution) {
            charts.evolution.updateSeries([{
                name: 'Entreprises créées',
                data: generateRandomData(12)
            }]);
        }
        
        showAlert('Tableau de bord actualisé', 'success');
        logActivity('dashboard_refreshed');
    }, 1000);
}

/**
 * Recherche d'entreprises
 */
function searchCompanies(query) {
    if (!dashboardData.companies) return [];
    
    const searchTerm = query.toLowerCase();
    return dashboardData.companies.filter(company => 
        company.name.toLowerCase().includes(searchTerm) ||
        company.nif.includes(searchTerm) ||
        company.segment.toLowerCase().includes(searchTerm) ||
        company.sector.toLowerCase().includes(searchTerm)
    );
}

/**
 * Génération de données aléatoires pour les graphiques
 */
function generateRandomData(count) {
    return Array.from({ length: count }, () => Math.floor(Math.random() * 50) + 10);
}

