/**
 * Mise à jour du badge de notifications
 */
function updateNotificationBadge(count) {
    const badge = document.getElementById('notificationsBadge');
    if (badge) {
        badge.textContent = count;
        badge.style.display = count > 0 ? 'block' : 'none';
    }
}

/**
 * Démarrage de l'actualisation automatique
 */
function startAutoRefresh() {
    if (refreshTimer) {
        clearInterval(refreshTimer);
    }
    
    refreshTimer = setInterval(() => {
        console.log('🔄 Actualisation automatique du dashboard');
        loadDashboardData();
    }, CONFIG.refreshInterval);
}

/**
 * =====================================
 * FONCTIONS DE NAVIGATION
 * =====================================
 */

/**
 * Navigation entre sections
 */
function showSection(section) {
    console.log(`📍 Navigation vers la section: ${section}`);
    logActivity('navigation', { section });
    
    // Mise à jour de l'état actif dans la sidebar
    document.querySelectorAll('.sidebar .nav-link').forEach(link => {
        link.classList.remove('active');
    });
    
    // Ici on simule la navigation (dans un vrai environnement, on chargerait la page correspondante)
    showAlert(`Navigation vers ${section} (fonctionnalité à implémenter)`, 'info');
}

/**
 * Déconnexion
 */
function logout() {
    logActivity('logout');
    showAlert('Déconnexion en cours...', 'info');
    
    setTimeout(() => {
        // Ici on redirigerait vers la page de connexion
        window.location.reload();
    }, 1000);
}

